from flask import Flask, request, jsonify
import logging

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.DEBUG,
                    format='%(asctime)s %(levelname)s %(message)s',
                    handlers=[logging.FileHandler("app.log"),
                              logging.StreamHandler()])

def log_request(req):
    logging.debug("Headers: %s", req.headers)
    logging.debug("Body: %s", req.data.decode('utf-8'))
    logging.debug("User information: %s", req.remote_addr)

def log_response(res):
    logging.debug("Response: %s", res.get_data(as_text=True))
    return res

@app.before_request
def before_request():
    log_request(request)

@app.after_request
def after_request(response):
    return log_response(response)

@app.route('/login', methods=['POST'])
def login():
    auth_header = request.headers.get('Authorization')
    if not auth_header:
        logging.error("Authentication failed, missing token")
        return jsonify({'message': 'Authentication failed'}), 401
    # Dummy authentication check
    if auth_header == "Bearer validtoken":
        logging.info("Authentication successful for token: validtoken")
        return jsonify({'message': 'Login successful'})
    else:
        logging.error("Invalid token provided: %s", auth_header)
        return jsonify({'message': 'Authentication failed'}), 403

@app.route('/data', methods=['GET'])
def get_data():
    try:
        data = {"key": "value"} # Example data
        logging.debug("Data retrieval successful")
        return jsonify(data)
    except Exception as e:
        logging.error("Error retrieving data: %s", str(e))
        return jsonify({'error': 'Data retrieval failed'}), 500

if __name__ == '__main__':
    app.run(debug=True)